import type { ByteBufferType } from './structures';
type Argument = Record<string, unknown> | Array<unknown> | Date | Uint8Array | SerializedArgument;
type SerializedArgument = string | number | null | ByteBufferType;
export type SerializedOptions<Type> = Required<{
    [Property in keyof Type]: Type[Property] extends string ? string : Type[Property] extends number ? number : Type[Property] extends Record<string, unknown> ? string : Type[Property] extends string | Record<string, unknown> ? string : Type[Property] extends Array<unknown> ? string : Type[Property] extends Array<unknown> | undefined ? string : Type[Property] extends Record<string, unknown> | undefined ? string : Type[Property] extends Date ? number : Type[Property] extends Date | undefined ? number : Type[Property] extends string | undefined ? string : Type[Property] extends number | undefined ? number : Type[Property] extends Uint8Array ? ByteBufferType : unknown;
}>;
declare const serializeArguments: <T extends Record<string, Argument> = Record<string, Argument>>(args: T) => SerializedOptions<T>;
export { serializeArguments };
